// Moldovan bank tender/news URLs
// Edit this list to add/remove/update URLs
const companies = [
  { name: 'MAIB', url: 'https://maib.md/ro/achizitii', page_type: 'tenders', language: 'ro', active: true },
  { name: 'MAIB', url: 'https://maib.md/ro/noutati', page_type: 'news', language: 'ro', active: true },
  { name: 'MICB', url: 'https://micb.md/tendere/', page_type: 'tenders', language: 'ro', active: true },
  { name: 'MICB', url: 'https://micb.md/noutati/', page_type: 'news', language: 'ro', active: true },
  { name: 'Victoriabank', url: 'https://www.victoriabank.md/licitatii', page_type: 'tenders', language: 'ro', active: true },
  { name: 'Victoriabank', url: 'https://www.victoriabank.md/newsroom', page_type: 'news', language: 'ro', active: true },
  { name: 'ProCredit', url: 'https://procreditbank.md/ro/licitatii_curente', page_type: 'tenders', language: 'ro', active: true },
  { name: 'ProCredit', url: 'https://procreditbank.md/ro/news', page_type: 'news', language: 'ro', active: true },
  { name: 'Eximbank', url: 'https://eximbank.md/news', page_type: 'news', language: 'ro', active: true },
  { name: 'ComertBank', url: 'https://comertbank.md/news/', page_type: 'news', language: 'ro', active: true }
];

return companies
  .filter(c => c.active)
  .map(c => ({ json: c }));

const company = $('Loop Over Companies').item.json;
const response = $json;

// Get content from HTTP response
let raw = '';
if (typeof response.data === 'string') raw = response.data;
else if (typeof response === 'string') raw = response;
else if (response.body) raw = String(response.body);
else raw = JSON.stringify(response);

// Strip HTML to plain text for LLM consumption
function htmlToText(html) {
  let text = html;
  // Remove script/style/noscript blocks entirely
  text = text.replace(/<(script|style|noscript|svg|path|iframe)[^>]*>[\s\S]*?<\/\1>/gi, '');
  // Remove HTML comments
  text = text.replace(/<!--[\s\S]*?-->/g, '');
  // Convert common block elements to newlines
  text = text.replace(/<\/?(?:div|p|br|hr|h[1-6]|li|tr|td|th|section|article|header|footer|nav|ul|ol|table|blockquote)[^>]*>/gi, '\n');
  // Remove all remaining HTML tags
  text = text.replace(/<[^>]+>/g, ' ');
  // Decode common HTML entities
  text = text.replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ');
  // Collapse whitespace: multiple spaces to one, multiple newlines to max two
  text = text.replace(/[ \t]+/g, ' ');
  text = text.replace(/\n[ \t]*/g, '\n');
  text = text.replace(/\n{3,}/g, '\n\n');
  return text.trim();
}

const content = htmlToText(raw);

// Check for problems
const isError = response.error || (response.statusCode && response.statusCode >= 400);
const isTooShort = content.length < 200;
const isLoginWall = /login|sign.?in|authenticat/i.test(content) && content.length < 1000;
const isBlocked = /blocked|captcha|cloudflare|access.denied|forbidden/i.test(content) && content.length < 2000;

const contentValid = !isError && !isTooShort && !isLoginWall && !isBlocked;

let notes = 'OK';
if (!contentValid) {
  notes = [isError && 'HTTP error', isTooShort && 'Too short', isLoginWall && 'Login wall', isBlocked && 'Blocked'].filter(Boolean).join('; ');
}

return {
  json: {
    name: company.name,
    url: company.url,
    page_type: company.page_type,
    language: company.language || 'ro',
    content: content,
    content_valid: contentValid,
    content_length: content.length,
    raw_length: raw.length,
    fetch_method: 'direct',
    validation_notes: notes
  }
};

const company = $('Loop Over Companies').item.json;
const response = $json;

let content = '';
if (typeof response.data === 'string') content = response.data;
else if (typeof response === 'string') content = response;
else content = JSON.stringify(response);

// Strip any residual HTML tags (Jina usually returns markdown but just in case)
content = content.replace(/<[^>]+>/g, ' ').replace(/[ \t]+/g, ' ').replace(/\n{3,}/g, '\n\n').trim();

const contentValid = !response.error && content.length >= 200;

return {
  json: {
    name: company.name,
    url: company.url,
    page_type: company.page_type,
    language: company.language || 'ro',
    content: content,
    content_valid: contentValid,
    content_length: content.length,
    fetch_method: 'jina',
    validation_notes: contentValid ? 'OK (via Jina)' : 'Jina failed'
  }
};

return {
  json: {
    name: $json.name,
    url: $json.url,
    page_type: $json.page_type,
    items: [],
    items_count: 0,
    tenders_count: 0,
    fetch_status: 'failed',
    fetch_method: $json.fetch_method || 'none',
    validation_notes: $json.validation_notes
  }
};

const MAX_CHARS = 30000;
let content = $json.content || '';
if (content.length > MAX_CHARS) {
  content = content.substring(0, MAX_CHARS) + '\n[TRUNCATED]';
}

const today = new Date().toISOString().split('T')[0];

const systemPrompt = `You are an expert at extracting structured information from Moldovan bank websites.

Rules:
- Extract EVERY distinct news item, announcement, or tender/procurement notice from the page content
- For tenders: look for keywords like licitatie, licitație, achizitie, achiziție, tender, procurement, concurs, RFP, RFQ, тендер, закупка, конкурс
- Preserve the original title EXACTLY as written in the "title" field (do not translate)
- Always provide English translation in "title_en" and "summary_en"
- Convert relative dates (yesterday, 2 days ago, ieri) to absolute ISO dates using today's date
- If NO items are found, return {"items": [], "page_metadata": {"total_items_found": 0, "extraction_notes": "No items found"}}
- Do NOT hallucinate or invent items
- Resolve relative URLs using the base URL
- Set is_tender=true for any procurement/tender/acquisition/RFP item
- Set confidence 0.9+ for clear distinct items, lower for ambiguous ones
- Normalize all dates to YYYY-MM-DD format

Return valid JSON matching this schema:
{
  "items": [{
    "title": "original title",
    "title_en": "english translation",
    "type": "tender|news|announcement|job|event|other",
    "is_tender": true/false,
    "date": "YYYY-MM-DD",
    "deadline": "YYYY-MM-DD or null",
    "url": "full URL to item",
    "summary_en": "brief English summary",
    "original_language": "ro|ru|en",
    "confidence": 0.0-1.0
  }],
  "page_metadata": {
    "total_items_found": number,
    "page_language": "ro|ru|en",
    "has_pagination": true/false,
    "extraction_notes": "brief notes"
  }
}`;

const userMessage = `Company: ${$json.name}
URL: ${$json.url}
Page type: ${$json.page_type}
Language: ${$json.language || 'ro'}
Today's date: ${today}

--- PAGE CONTENT ---
${content}`;

const requestBody = {
  model: 'openai/gpt-4o-mini',
  max_tokens: 4096,
  temperature: 0.1,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userMessage }
  ]
};

return {
  json: {
    name: $json.name,
    url: $json.url,
    page_type: $json.page_type,
    language: $json.language,
    fetch_method: $json.fetch_method,
    content_length: $json.content_length,
    request_body: JSON.stringify(requestBody)
  }
};

const company = $('Prepare for LLM').item.json;
const response = $json;

// Extract LLM response content
let output;
try {
  const content = response.choices?.[0]?.message?.content;
  if (!content) throw new Error('No content in LLM response');
  output = JSON.parse(content);
} catch (e) {
  return {
    json: {
      name: company.name,
      url: company.url,
      page_type: company.page_type,
      items: [],
      items_count: 0,
      tenders_count: 0,
      fetch_status: 'extraction_error',
      fetch_method: company.fetch_method,
      validation_notes: 'LLM parse error: ' + e.message
    }
  };
}

let items = output.items || [];
const metadata = output.page_metadata || {};
const warnings = [];

// Sanity checks
if (items.length > 30) {
  warnings.push('Capped at 30 items (was ' + items.length + ')');
  items = items.slice(0, 30);
}

const before = items.length;
items = items.filter(i => (i.confidence || 0) >= 0.5);
if (items.length < before) {
  warnings.push('Removed ' + (before - items.length) + ' low-confidence items');
}

if (items.length === 0 && company.page_type === 'tenders') {
  warnings.push('Tender page returned 0 items');
}

const today = new Date().toISOString().split('T')[0];
items = items.map(i => ({
  ...i,
  company: company.name,
  source_url: company.url,
  found_date: today
}));

return {
  json: {
    name: company.name,
    url: company.url,
    page_type: company.page_type,
    items: items,
    items_count: items.length,
    tenders_count: items.filter(i => i.is_tender).length,
    fetch_status: 'success',
    fetch_method: company.fetch_method,
    content_length: company.content_length,
    model: response.model || 'unknown',
    usage: response.usage || {},
    page_metadata: {
      ...metadata,
      sanity_warnings: warnings.length > 0 ? warnings : undefined
    }
  }
};

const items = $input.all();
const allResults = items.map(i => i.json);
const successful = allResults.filter(r => r.fetch_status === 'success');
const failed = allResults.filter(r => r.fetch_status !== 'success');
const allItems = successful.flatMap(r => r.items || []);
const tenders = allItems.filter(i => i.is_tender);

const totalUsage = successful.reduce((acc, r) => {
  const u = r.usage || {};
  return {
    prompt_tokens: (acc.prompt_tokens || 0) + (u.prompt_tokens || 0),
    completion_tokens: (acc.completion_tokens || 0) + (u.completion_tokens || 0),
    total_tokens: (acc.total_tokens || 0) + (u.total_tokens || 0)
  };
}, {});

const summary = {
  run_date: new Date().toISOString(),
  urls_checked: allResults.length,
  urls_succeeded: successful.length,
  urls_failed: failed.length,
  total_items: allItems.length,
  tenders_found: tenders.length,
  news_found: allItems.length - tenders.length,
  token_usage: totalUsage,
  failed_urls: failed.map(r => ({ name: r.name, url: r.url, reason: r.validation_notes })),
  warnings: successful.flatMap(r => {
    const w = r.page_metadata?.sanity_warnings || [];
    return w.map(warning => ({ company: r.name, warning }));
  })
};

return [
  { json: { type: 'run_summary', ...summary } },
  ...allItems.map(i => ({ json: { type: 'extracted_item', ...i } }))
];

const crypto = require('crypto');
const fs = require('fs');
const SEEN_FILE = '/var/lib/n8n/tender-monitor/seen-hashes.json';

// Load existing hashes
let seen = {};
try { seen = JSON.parse(fs.readFileSync(SEEN_FILE, 'utf8')); } catch {}

const items = $input.all();
const summary = items[0].json;
const extractedItems = items.slice(1).map(i => i.json);

// Dedup
const newItems = [];
for (const item of extractedItems) {
  const normalized = (item.company + '|' + item.title).toLowerCase()
    .replace(/[^\w\s|]/g, '').replace(/\s+/g, ' ').trim();
  const hash = crypto.createHash('sha256').update(normalized).digest('hex').slice(0, 16);
  if (!seen[hash]) {
    seen[hash] = { date: new Date().toISOString().split('T')[0], title: item.title };
    newItems.push({ ...item, dedup_hash: hash });
  }
}

// Save updated hashes
fs.mkdirSync('/var/lib/n8n/tender-monitor', { recursive: true });
fs.writeFileSync(SEEN_FILE, JSON.stringify(seen, null, 2));

// Output: updated summary + new items only
return [
  { json: { ...summary, new_items: newItems.length, total_before_dedup: extractedItems.length } },
  ...newItems.map(i => ({ json: i }))
];

const items = $input.all();
const summary = items[0].json;
const newItems = items.slice(1).map(i => i.json);
const newTenders = newItems.filter(i => i.is_tender);
const newNews = newItems.filter(i => !i.is_tender);

// Always send a daily digest
let lines = [];

if (newTenders.length > 0) {
  lines.push('\ud83d\udce2 *New Tenders Found*\n');
  for (const t of newTenders) {
    let line = `*${t.company}* \u2014 ${t.title_en || t.title}`;
    const meta = [];
    if (t.date) meta.push(`\ud83d\udcc5 ${t.date}`);
    if (t.deadline) meta.push(`\u23f0 Deadline: ${t.deadline}`);
    if (t.url) meta.push(`[View](${t.url})`);
    if (meta.length) line += '\n' + meta.join(' | ');
    lines.push(line);
  }
  lines.push('');
}

// Daily digest summary
lines.push(`\ud83d\udcca *Daily Scan Complete*`);
lines.push(`URLs: ${summary.urls_succeeded}/${summary.urls_checked} | Items: ${summary.total_before_dedup} | New: ${newTenders.length} tenders, ${newNews.length} news`);

if (summary.urls_failed > 0) {
  const failedNames = (summary.failed_urls || []).map(f => f.name).join(', ');
  lines.push(`\u26a0\ufe0f Failed: ${failedNames}`);
}

const text = lines.join('\n');

return [{ json: { text, chat_id: '364749075', has_new_tenders: newTenders.length > 0 } }];
